  const db = new Dirty();

  db.set(1, {test: 'foo'});
  db.set(2, {test: 'bar'});
  db.set(3, {test: 'foobar'});

  it('should return each doc key and contents', async function () {
    let i = 0;
    db.forEach((key, doc) => {
      i++;
      assert.equal(key, i);
